static void ui_setting_screen_keyboard_handler(lv_event_t * e)
{
    lv_key_t key = lv_event_get_key(e);

    switch (key) {
        case LV_KEY_UP:
        case LV_KEY_LEFT:
            ui_setting_screen_focus_prev();
            break;
        case LV_KEY_PREV:
            break;
        case LV_KEY_DOWN:
        case LV_KEY_RIGHT:
            ui_setting_screen_focus_next();
            break;
        case LV_KEY_NEXT:
            break;
        case LV_KEY_ENTER:
            ui_setting_screen_keyboard_enter();
            break;
        case LV_KEY_ESC:
            _ui_screen_change(&ui_home_screen, LV_SCR_LOAD_ANIM_FADE_ON, 0, 0, &ui_home_screen_screen_init);
            break;
        default:
            break;
    }
}

// option change callback functions
static void ui_setting_option_change_callback_backlight(lv_obj_t ** children)
{
    lv_obj_t * options = children[UI_COMP_LIST_ITEM_RIGHT_OPTIONS];
    const char * options_text = lv_label_get_text(options);

    if (strncmp(options_text, "ON", 2) == 0) {
        lv_label_set_text(options, "OFF");
    } else {
        lv_label_set_text(options, "ON");
    }
}

static void ui_setting_option_change_callback_sleep_time(lv_obj_t ** children)
{
    // 1 Min -> 3 Min -> 5 Min -> 15 Min -> 30 Min
    lv_obj_t * options = children[UI_COMP_LIST_ITEM_RIGHT_OPTIONS];
    const char * options_text = lv_label_get_text(options);

    if (strncmp(options_text, "1 Min", 5) == 0) {
        lv_label_set_text(options, "3 Min");
    } else if (strncmp(options_text, "3 Min", 5) == 0) {
        lv_label_set_text(options, "5 Min");
    } else if (strncmp(options_text, "5 Min", 5) == 0) {
        lv_label_set_text(options, "15 Min");
    }
    else if (strncmp(options_text, "15 Min", 7) == 0) {
        lv_label_set_text(options, "30 Min");
    } else {
        lv_label_set_text(options, "1 Min");
    }
}

static void ui_setting_option_change_callback_language(lv_obj_t ** children)
{
    // English -> Chinese

    lv_obj_t * options = children[UI_COMP_LIST_ITEM_RIGHT_OPTIONS];
    const char * options_text = lv_label_get_text(options);

    if (strncmp(options_text, "English", 7) == 0) {
        // TODO: Change language to Chinese
    } else {
        lv_label_set_text(options, "English");
    }
}

static void ui_setting_focus_obj_by_index(int32_t index)
{
    if (index == __focus_obj_current_index || index < 0 || index >= UI_SETTING_FOCUS_OBJ_COUNT) {
        return;
    }
    
    // Clear current focus object
    if (__focus_obj_current_index >= 0) {
        lv_obj_send_event(__focus_obj_list[__focus_obj_current_index], LV_EVENT_DEFOCUSED, NULL);
    }
    __focus_obj_current_index = index;
    lv_obj_send_event(__focus_obj_list[index], LV_EVENT_FOCUSED, NULL);
}

void ui_setting_option_change_callback(lv_event_t * e)
{
    lv_obj_t ** children = (lv_obj_t **)lv_event_get_user_data(e);
    lv_obj_t * setting_item_container = children[UI_COMP_LIST_ITEM_LIST_ITEM];

    // Check if the currently focused object is the current setting item; if not, set it as the focused setting item
    if (setting_item_container != __focus_obj_list[__focus_obj_current_index]) {
        for (int i = 0; i < UI_SETTING_FOCUS_OBJ_COUNT; i++) {
            if (setting_item_container == __focus_obj_list[i]) {
                ui_setting_focus_obj_by_index(i);
                return;
            }
        }
    }

    // If the focused object is the current setting item, call the option change callback function
    if (setting_item_container == __focus_obj_list[__focus_obj_current_index]) {
        if (setting_item_container == ui_setting_screen_backlight) {
            ui_setting_option_change_callback_backlight(children);
        } else if (setting_item_container == ui_setting_screen_sleep_time) {
            ui_setting_option_change_callback_sleep_time(children);
        } else if (setting_item_container == ui_setting_screen_language) {
            ui_setting_option_change_callback_language(children);
        }
    }
}
